mapper.select:
SELECT id, conversation_id, mailbox_id, run_id, sender, message_type, body, reply_to_message_id, metadata_json, read_at, ack_at, created_at, updated_at FROM mailbox_messages WHERE conversation_id = #{conversationId}
AND (created_at > #{afterCreatedAt} OR (created_at = #{afterCreatedAt} AND id > #{afterId}))
ORDER BY created_at ASC, id ASC

SELECT id, conversation_id, mailbox_id, run_id, sender, message_type, body,
       reply_to_message_id, metadata_json, read_at, ack_at, created_at, updated_at
FROM mailbox_messages
WHERE conversation_id = #{conversationId}
  AND id = #{messageId}

mapper.update:
UPDATE mailbox_messages
SET read_at = #{readAt},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE mailbox_messages
SET ack_at = #{ackAt},
    updated_at = #{updatedAt}
WHERE id = #{id}
